INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('071919cc-277d-48e7-92d3-12693d195e4b', 'b55320f9-69ea-4a06-97cb-0afc10bac68f', '科室验重', 'doctor telephone validate', 'trigger', '\nrepeat_error = create_validation_trigger_rule_errors(u\'科室已存在，不允许重复创建\')\nif instance.id:\n    department_co=CustomObjects7.objects.filter(deleted=0, picklist_1=instance.picklist_1, account_1_id=instance.account_1_id).exclude(id=instance.id)\nelse:\n    department_co=CustomObjects7.objects.filter(deleted=0, picklist_1=instance.picklist_1, account_1_id=instance.account_1_id)\n    print instance.picklist_1,instance.account_1_id,u\'112233\'\n    \nm_a = department_co[0] if department_co else None\nif m_a:\n    raise repeat_error\n', '', '0', '1', '2019-06-24 11:08:57', '1', '2020-09-02 05:58:10', 'pre_save', '1', 'custom', 'cs_doctor_telephone_validate', '1');

-- 修改会议费用测算trigger
UPDATE `object_validations` SET `trigger_code` = 'from orionbase.common import models\nfrom decimal import Decimal\ntotal_expense = sum(\ninstance.eventexpenses_set.filter(deleted=0, total_expense__isnull=False).values_list(\'total_expense\', flat=True))\nexpenses = Decimal(total_expense).quantize(Decimal(\'0.00\'))\nif instance.record_type.name.endswith(\'__report\'):\n    event_budget = Decimal(instance.event_budget).quantize(Decimal(\'0.00\'))\n    if str(expenses) and str(event_budget):\n        expenses_diff = max(expenses - event_budget, 0)\n    else:\n        expenses_diff = 0\n    models.Events.advance_objects.filter(id=instance.id).update(event_expense=expenses,\n                                                                number_4=expenses_diff\n                                                                )\nelse:\n    models.Events.advance_objects.filter(id=instance.id).update(event_budget=expenses)' WHERE (`id` = '6bc74574-a65e-43ea-8ab9-b101ba66119d');
UPDATE `object_validations` SET `trigger_code` = 'from orionbase.common import models\nfrom decimal import Decimal\nspeaker_expense = 0\ntotal_expense = sum(\ninstance.event.eventexpenses_set.filter(deleted=0, total_expense__isnull=False).values_list(\'total_expense\',flat=True))\nexpenses = Decimal(total_expense).quantize(Decimal(\'0.00\'))\nif instance.event.record_type.name.endswith(\'__report\'):\n    event_budget = Decimal(instance.event.event_budget).quantize(Decimal(\'0.00\'))\n    if str(expenses) and str(event_budget):\n        expenses_diff = max(expenses - event_budget, 0)\n    else:\n        expenses_diff = 0\n    models.Events.advance_objects.filter(id=instance.event.id).update(event_expense=expenses,\n                                                                      number_4=expenses_diff\n                                                                )\nelse:\n    models.Events.advance_objects.filter(id=instance.event.id).update(event_budget=expenses)' WHERE (`id` = 'h0052552-e0e1-11e8-b6c8-02f90e0f46f3');
UPDATE `object_validations` SET `trigger_code` = 'from orionbase.common import models\nuserid = instance.owner.id\n# 报告阶段自动拷贝计划阶段成本中心\nif (instance.state.name == \'save\' and instance.record_type.name.endswith(\'__report\')):\n    if instance.id and instance.event_id:\n        if not models.CustomObjects4.objects.filter(deleted=0,event_1_id=instance.id).exists():\n            to_copy_cost = []\n            from_cost_data = models.CustomObjects4.objects.filter(deleted=0,event_1_id=instance.event_id)\n            if from_cost_data:\n                for data in from_cost_data:\n                    data.id = None\n                    data.event_1_id = instance.id\n                    to_copy_cost.append(data)\n            if to_copy_cost:\n                models.CustomObjects4.objects.bulk_create(to_copy_cost, batch_size=500)' WHERE (`id` = 'f083128a-5353-4ab0-b4ac-462307111ee0');

